const SUPABASE_URL = '<OPTIMAL_SUPABASE_URL>';
const SUPABASE_KEY = '<OPTIMAL_SUPABASE_SERVICE_KEY>';
const STRAPI_URL = '<STRAPI_BASE_URL>';
const STRAPI_TOKEN = '<STRAPI_TOKEN>';

// Step 1: Fetch approved posts from Supabase
const approvedRes = await fetch(
  `${SUPABASE_URL}/rest/v1/content_generated_posts?status=eq.approved&order=created_at.asc&limit=10`,
  { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` } }
);
const approvedPosts = await approvedRes.json();

if (!approvedPosts.length) {
  return [{ json: { synced: 0, message: 'No approved posts to sync' } }];
}

let synced = 0;
let failed = 0;
const results = [];

for (const post of approvedPosts) {
  try {
    // Step 2: Create social post in Strapi
    const strapiRes = await fetch(`${STRAPI_URL}/api/social-posts`, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${STRAPI_TOKEN}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        data: {
          headline: (post.content || '').substring(0, 100),
          body: post.content,
          platform: post.platform,
          brand: 'OPTIMAL',
          scheduled_date: new Date().toISOString().split('T')[0],
          delivery_status: 'pending',
          campaign_ref: post.campaign_id,
        }
      })
    });

    if (!strapiRes.ok) {
      const errText = await strapiRes.text();
      results.push({ id: post.id, status: 'failed', error: errText });
      failed++;
      continue;
    }

    const strapiData = await strapiRes.json();
    const documentId = strapiData.data?.documentId || strapiData.data?.id;

    // Step 3: Update Supabase post status to 'posted'
    const updateRes = await fetch(
      `${SUPABASE_URL}/rest/v1/content_generated_posts?id=eq.${post.id}`,
      {
        method: 'PATCH',
        headers: {
          apikey: SUPABASE_KEY,
          Authorization: `Bearer ${SUPABASE_KEY}`,
          'Content-Type': 'application/json',
          Prefer: 'return=minimal',
        },
        body: JSON.stringify({
          status: 'posted',
          posted_at: new Date().toISOString(),
        })
      }
    );

    results.push({ id: post.id, status: 'synced', strapi_document_id: documentId });
    synced++;
  } catch (err) {
    results.push({ id: post.id, status: 'failed', error: err.message });
    failed++;
  }
}

return [{ json: { synced, failed, total: approvedPosts.length, results } }];
